var result,fileName,originCountrySelector=$("#origin-country-selector"),destinationCountrySelector=$("#destination-country-selector"),body=$("body"),githubDbFolder="/data/documents/",availableCountries=[{code:"RO",name:"Romania",file:"romania.json"}];function buildOriginCountrySelector(e){originCountrySelector.append('<option value="">Selectează o țară</option>');for(let t=0;t<e.length;t++){var o=e[t];o&&originCountrySelector.append(`<option value="${o.file}">${o.name}</option>`)}}function buildDestinationCountrySelector(e){for(let t=0;t<e.length;t++){var o=e[t];o.documents&&destinationCountrySelector.append(`<option value="${o.code}">${o.name}</option>`)}}function findCountry(e,o){return o.find(o=>o.code===e)}function buildResults(e){var o=$("#info"),t=$("#comment"),n=$("#source"),i=$("#result");o.text(`Pentru a călători în ${e.name} ai nevoie de ${e.documents}.`),t.text(e.comment),n.html(`<a target="_blank" rel="noopener" href="${e.source}">Sursa informațiilor</a>`),i.show(),body.toggleClass("results-visible")}function buildEditLink(e){$("#edit").html(`<a target="_blank" rel="noopener" href="${githubDbFolder}/${e}"><i class="fal fa-edit"></i> Corectează informațiile</a>`)}buildOriginCountrySelector(availableCountries),originCountrySelector.change((function(){fileName=$(this).val(),$.getJSON("/data/documents/"+fileName,(function(e){result=e,console.log(e)}))})),destinationCountrySelector.change((function(){buildResults(findCountry($(this).val(),result)),buildEditLink(fileName)})),$("#toggle-menu").click((function(){$("body").toggleClass("menu-visible")}));